// Definição do nó
class Node {
    public int Value;
    public Node Next;
    public Node(int value) { Value = value; }
}

// Inserção no início — O(1)
void InsertBegin(ref Node head, int value) {
    Node newNode = new Node(value);
    newNode.Next = head;  // aponta para o antigo HEAD
    head = newNode;       // HEAD passa a ser o novo nó
}

