type Node struct {
	Value int
	Next  *Node
}

func insertBegin(head **Node, value int) {
	newNode := &Node{Value: value}
	newNode.Next = *head // aponta para o antigo HEAD
	*head = newNode      // HEAD passa a ser o novo nó
}

