    def __init__(self, value):
        self.value = value
        self.next = None  # ponteiro para o próximo nó

class SinglyLinkedList:
    def __init__(self):
        self.head = None

    def insert_begin(self, value):
        new_node = Node(value)
        new_node.next = self.head  # aponta para o antigo HEAD
        self.head = new_node       # HEAD passa a ser o novo nó

codeSnippets.javascript:
class Node {
    constructor(value) {
        this.value = value;
        this.next = null;  // ponteiro para o próximo nó
    }
}

class SinglyLinkedList {
    constructor() { this.head = null; }

    insertBegin(value) {
        const node = new Node(value);
        node.next = this.head;  // aponta para o antigo HEAD
        this.head = node;       // HEAD passa a ser o novo nó
    }
}
